  vtr::vector<CircuitEdgeId, CircuitPortId> edge_sink_port_ids_;
  vtr::vector<CircuitEdgeId, size_t> edge_sink_pin_ids_;
  vtr::vector<CircuitEdgeId, std::vector<float>>
