1	/************************************************************************
2	 * Function to perform fundamental operation for the circuit library
3	 * These functions are not universal methods for the CircuitLibrary class
4	 * They are made to ease the development in some specific purposes
5	 * Please classify such functions in this file
6	 ***********************************************************************/
7	
8	#include <algorithm>
9	
10	/* Headers from vtrutil library */
11	#include "check_circuit_library.h"
12	#include "circuit_library_utils.h"
13	#include "decoder_library_utils.h"
14	#include "vtr_assert.h"
15	#include "vtr_log.h"
16	
17	/* begin namespace openfpga */
18	namespace openfpga {
19	
20	/********************************************************************
21	 * Get the model id of a SRAM model that is used to configure
22	 * a circuit model
23	 *******************************************************************/
24	std::vector<CircuitModelId> find_circuit_sram_models(
25	  const CircuitLibrary& circuit_lib, const CircuitModelId& circuit_model) {
26	  /* SRAM model id is stored in the sram ports of a circuit model */
27	  std::vector<CircuitPortId> sram_ports =
28	    circuit_lib.model_ports_by_type(circuit_model, CIRCUIT_MODEL_PORT_SRAM);
29	  std::vector<CircuitModelId> sram_models;
30	
31	  /* Create a list of sram models, but avoid duplicated model ids */
32	  for (const auto& sram_port : sram_ports) {
33	    CircuitModelId sram_model = circuit_lib.port_tri_state_model(sram_port);
34	    VTR_ASSERT(true == circuit_lib.valid_model_id(sram_model));
35	    if (sram_models.end() !=
36	        std::find(sram_models.begin(), sram_models.end(), sram_model)) {
37	      continue; /* Already in the list, skip the addition */
38	    }
39	    /* Not in the list, add it */
40	    sram_models.push_back(sram_model);
41	  }
42	
43	  return sram_models;
44	}
45	
46	/********************************************************************
47	 * Find regular (not mode select) sram ports of a circuit model
48	 *******************************************************************/
49	std::vector<CircuitPortId> find_circuit_regular_sram_ports(
50	  const CircuitLibrary& circuit_lib, const CircuitModelId& circuit_model) {
51	  std::vector<CircuitPortId> sram_ports = circuit_lib.model_ports_by_type(
52	    circuit_model, CIRCUIT_MODEL_PORT_SRAM, true);
53	  std::vector<CircuitPortId> regular_sram_ports;
54	
55	  for (const auto& port : sram_ports) {
56	    if (true == circuit_lib.port_is_mode_select(port)) {
57	      continue;
58	    }
59	    regular_sram_ports.push_back(port);
60	  }
61	
62	  return regular_sram_ports;
63	}
64	
65	/********************************************************************
66	 * Find mode select sram ports of a circuit model
67	 *******************************************************************/
68	std::vector<CircuitPortId> find_circuit_mode_select_sram_ports(
69	  const CircuitLibrary& circuit_lib, const CircuitModelId& circuit_model) {
70	  std::vector<CircuitPortId> sram_ports = circuit_lib.model_ports_by_type(
71	    circuit_model, CIRCUIT_MODEL_PORT_SRAM, true);
72	  std::vector<CircuitPortId> mode_select_sram_ports;
73	
74	  for (const auto& port : sram_ports) {
75	    if (false == circuit_lib.port_is_mode_select(port)) {
76	      continue;
77	    }
78	    mode_select_sram_ports.push_back(port);
79	  }
80	
81	  return mode_select_sram_ports;
82	}
83	
84	/********************************************************************
85	 * Find the number of shared configuration bits for a ReRAM circuit
86	 * TODO: this function is subjected to be changed due to ReRAM-based SRAM cell
87	 *design!!!
88	 *******************************************************************/
89	static size_t find_rram_circuit_num_shared_config_bits(
90	  const CircuitLibrary& circuit_lib, const CircuitModelId& rram_model,
91	  const e_config_protocol_type& sram_orgz_type) {
92	  size_t num_shared_config_bits = 0;
93	
94	  /* Branch on the organization of configuration protocol */
95	  switch (sram_orgz_type) {
96	    case CONFIG_MEM_STANDALONE:
97	    case CONFIG_MEM_SCAN_CHAIN:
98	      break;
99	    case CONFIG_MEM_QL_MEMORY_BANK:
100	    case CONFIG_MEM_MEMORY_BANK: {
101	      /* Find BL/WL ports */
102	      std::vector<CircuitPortId> blb_ports =
103	        circuit_lib.model_ports_by_type(rram_model, CIRCUIT_MODEL_PORT_BLB);
104	      for (auto blb_port : blb_ports) {
105	        num_shared_config_bits =
106	          std::max((int)num_shared_config_bits,
107	                   (int)circuit_lib.port_size(blb_port) - 1);
108	      }
109	      break;
110	    }
111	    default:
112	      VTR_LOG_ERROR("Invalid type of SRAM organization!\n");
113	      exit(1);
114	  }
115	
116	  return num_shared_config_bits;
117	}
