121	 * for circuit model
122	 * It will return 0 for CMOS circuits
123	 * It will return the maximum shared configuration bits across ReRAM models
124	 *
125	 * Note: This function may give WRONG results when all the SRAM ports
126	 * are not properly linked to its circuit models!
127	 * So, it should be called after the SRAM linking is done!!!
128	 *
129	 * IMPORTANT: This function should NOT be used to find the number of shared
130	 *configuration bits for a multiplexer, because the multiplexer size is
131	 *determined during the FPGA architecture generation (NOT during the XML
132	 *parsing).
133	 *******************************************************************/
134	size_t find_circuit_num_shared_config_bits(
135	  const CircuitLibrary& circuit_lib, const CircuitModelId& circuit_model,
136	  const e_config_protocol_type& sram_orgz_type) {
137	  size_t num_shared_config_bits = 0;
138	
139	  std::vector<CircuitPortId> sram_ports =
140	    circuit_lib.model_ports_by_type(circuit_model, CIRCUIT_MODEL_PORT_SRAM);
141	  for (auto sram_port : sram_ports) {
142	    CircuitModelId sram_model = circuit_lib.port_tri_state_model(sram_port);
143	    VTR_ASSERT(true == circuit_lib.valid_model_id(sram_model));
144	
145	    /* Depend on the design technolgy of SRAM model, the number of configuration
146	     * bits will be different */
147	    switch (circuit_lib.design_tech_type(sram_model)) {
148	      case CIRCUIT_MODEL_DESIGN_CMOS:
149	        /* CMOS circuit do not need shared configuration bits */
150	        break;
151	      case CIRCUIT_MODEL_DESIGN_RRAM:
152	        /* RRAM circuit do need shared configuration bits, but it is subjected
153	         * to the largest one among different SRAM models */
154	        num_shared_config_bits =
155	          std::max((int)num_shared_config_bits,
156	                   (int)find_rram_circuit_num_shared_config_bits(
157	                     circuit_lib, sram_model, sram_orgz_type));
158	        break;
159	      default:
160	        VTR_LOGF_ERROR(__FILE__, __LINE__,
161	                       "Invalid design technology for SRAM model!\n");
162	        exit(1);
163	    }
164	  }
165	
166	  return num_shared_config_bits;
