190	  switch (config_protocol_type) {
191	    case CONFIG_MEM_FEEDTHROUGH:
192	    case CONFIG_MEM_STANDALONE:
193	    case CONFIG_MEM_SCAN_CHAIN:
194	    case CONFIG_MEM_QL_MEMORY_BANK:
195	    case CONFIG_MEM_MEMORY_BANK: {
196	      break;
197	    }
198	    case CONFIG_MEM_FRAME_BASED: {
199	      /* For frame-based configuration protocol
200	       * The number of configuration bits is the address size
201	       */
202	      if (0 < num_config_bits) {
203	        num_config_bits = find_mux_local_decoder_addr_size(num_config_bits);
204	      }
205	      break;
206	    }
207	    default:
