301	/************************************************************************
302	 * Advanced check if the circuit model of configurable memory
303	 * satisfy the needs of configuration protocol
304	 * - Configuration chain -based: we check if we have a CCFF model
305	 * - Flatten/Frame -based: we check if we have a SRAM model which has BL and WL
306	 * - Memory bank: we check if we have a SRAM model. Also we need to check if we
307	 *have valid CCFF models for BL/WL models (if selected)
308	 ***********************************************************************/
309	bool check_configurable_memory_circuit_model(
310	  const ConfigProtocol& config_protocol, const CircuitLibrary& circuit_lib) {
311	  size_t num_err = 0;
312	  CircuitModelId config_mem_circuit_model = config_protocol.memory_model();
313	
314	  switch (config_protocol.type()) {
315	    case CONFIG_MEM_SCAN_CHAIN:
316	      num_err =
317	        check_ccff_circuit_model_ports(circuit_lib, config_mem_circuit_model);
318	      break;
319	    case CONFIG_MEM_QL_MEMORY_BANK: {
320	      num_err = check_sram_circuit_model_ports(circuit_lib,
321	                                               config_mem_circuit_model, true);
322	      /* Check circuit model for BL protocol */
323	      CircuitModelId bl_memory_model = config_protocol.bl_memory_model();
324	      if (BLWL_PROTOCOL_SHIFT_REGISTER == config_protocol.bl_protocol_type() &&
325	          CircuitModelId::INVALID() == bl_memory_model) {
326	        VTR_LOG_ERROR("Expect a valid CCFF circuit model for BL protocol");
327	        num_err++;
328	      }
329	      if (bl_memory_model) {
330	        num_err +=
331	          check_bl_ccff_circuit_model_ports(circuit_lib, bl_memory_model);
332	      }
333	
334	      /* Check circuit model for WL protocol */
335	      CircuitModelId wl_memory_model = config_protocol.wl_memory_model();
336	      if (BLWL_PROTOCOL_SHIFT_REGISTER == config_protocol.wl_protocol_type() &&
337	          CircuitModelId::INVALID() == wl_memory_model) {
338	        VTR_LOG_ERROR("Expect a valid CCFF circuit model for WL protocol");
339	        num_err++;
340	      }
341	      if (wl_memory_model) {
342	        num_err +=
343	          check_wl_ccff_circuit_model_ports(circuit_lib, wl_memory_model);
344	      }
345	      break;
346	    }
347	    case CONFIG_MEM_STANDALONE:
348	    case CONFIG_MEM_MEMORY_BANK:
349	    case CONFIG_MEM_FRAME_BASED:
350	      num_err = check_sram_circuit_model_ports(circuit_lib,
351	                                               config_mem_circuit_model, true);
352	
353	      break;
354	    default:
355	      VTR_LOGF_ERROR(__FILE__, __LINE__,
356	                     "Invalid type of configuration protocol!\n");
357	      return false;
358	  }
359	
360	  VTR_LOG(
361	    "Found %ld errors when checking configurable memory circuit models!\n",
362	    num_err);
363	  return (0 == num_err);
364	}
